export function groupMicroSaaSByCategory(products: MicroSaaSProduct[] = microSaasCatalog): Record<string, MicroSaaSProduct[]> {
  const groups: Record<string, MicroSaaSProduct[]> = {};
  for (const p of products) {
    if (!groups[p.category]) groups[p.category] = [];
    groups[p.category].push(p);
  }
  return groups;
}

export const microSaasCategories = Object.keys(groupMicroSaaSByCategory()).sort();
export const microSaasTotal = microSaasCatalog.length;
